changeSet.sql:
CREATE TYPE QuestionType AS ENUM ('Organization', 'Vendor', 'Cloud', 'Both', 'GDPRSystem', 'GDPROrganization');
ALTER TABLE qualitative_questions
	ALTER COLUMN vendor_type DROP DEFAULT,
	ALTER COLUMN vendor_type type QuestionType using vendor_type::text::QuestionType,
	ALTER COLUMN vendor_type SET DEFAULT 'Organization';

ALTER TABLE qualitative_questions ADD COLUMN code character varying (32) DEFAULT NULL;
CREATE INDEX i_qualitative_question_risk_model_code ON qualitative_questions (code, risk_model_id);
